import { mkdir, writeFile } from "node:fs/promises";
import { join } from "node:path";

const write = async (root, path, value) => { const target = join(root, path); await mkdir(join(target, ".."), { recursive: true }); await writeFile(target, `${JSON.stringify(value, null, 2)}\n`); };
export function algorithmsBatch({ count = 40, invalid = false, duplicate = false, badReference = false } = {}) {
  const items = Array.from({ length: count }, (_, index) => ({ id: duplicate && index === count - 1 ? "test-algorithm-1" : `test-algorithm-${index + 1}`, prompt: "technical fixture", feedbackModel: { decisionSignal: "fixture reason", details: "fixture details", distractorExplanations: { no: "fixture explanation" } }, options: [{ id: "yes", text: "yes", isCorrect: true }, { id: "no", text: "no", isCorrect: false }], ...(invalid && index === 0 ? { feedbackModel: { decisionSignal: "fixture reason", details: "" } } : {}) }));
  return { schemaVersion: "manual-source-v1", sourceBatchId: "fixture-algorithms", trackId: "algorithms", familyId: "algorithms", contentVersion: "algorithms-fixture-v1", taxonomyVersion: "algorithms-taxonomy-v1", declaredModes: ["algorithms-interview-simulation"], provenance: { sourceRepository: "fixture", sourceReference: "fixture" }, groups: [{ roadmapNodeId: badReference ? "unknown" : "arrays_and_strings", itemIds: items.map((item) => item.id) }], items };
}
export function certificationBatch({ count = 50 } = {}) { const items = Array.from({ length: count }, (_, index) => ({ id: `test-certification-${index + 1}`, prompt: "technical fixture", feedbackModel: { decisionSignal: "fixture reason", details: "fixture details", distractorExplanations: { no: "fixture explanation" } }, options: [{ id: "yes", text: "yes", isCorrect: true }, { id: "no", text: "no", isCorrect: false }], taxonomyRefs: [{ axisId: "cloud-domain", nodeId: "fixture-domain" }] })); return { schemaVersion: "manual-source-v1", sourceBatchId: "fixture-certification", trackId: "cloud-certification", familyId: "certification", contentVersion: "certification-fixture-v1", taxonomyVersion: "cloud-certification-taxonomy-v1", declaredModes: ["cloud-practice", "cloud-exam-simulation"], provenance: { sourceRepository: "fixture", sourceReference: "fixture" }, items }; }
export async function fixtureRoot(root, { algorithms, certification, approvals = true, legacy = false } = {}) {
  await write(root, "config/families/algorithms.json", { schemaVersion: "family-config-v1", familyId: "algorithms", supportedInteractions: ["choice", "ordering", "complexity"], modes: [{ id: "algorithms-interview-simulation", minimumPool: 40, fixedLength: 40 }] });
  await write(root, "config/families/certification.json", { schemaVersion: "family-config-v1", familyId: "certification", supportedInteractions: ["choice"], modes: [{ id: "cloud-practice", minimumPool: 10 }, { id: "cloud-exam-simulation", minimumPool: 50 }] });
  await write(root, "config/tracks/algorithms.json", { schemaVersion: "track-config-v1", trackId: "algorithms", familyId: "algorithms", taxonomyVersion: "algorithms-taxonomy-v1", taxonomyPath: "config/taxonomy/algorithms.json" });
  await write(root, "config/tracks/cloud-certification.json", { schemaVersion: "track-config-v1", trackId: "cloud-certification", familyId: "certification", taxonomyVersion: "cloud-certification-taxonomy-v1", taxonomyPath: "config/taxonomy/cloud-certification.json", profile: null });
  await write(root, "config/taxonomy/algorithms.json", { schemaVersion: "taxonomy-config-v1", trackId: "algorithms", taxonomyVersion: "algorithms-taxonomy-v1", nodes: ["arrays_and_strings"] });
  await write(root, "config/taxonomy/cloud-certification.json", { schemaVersion: "taxonomy-config-v1", trackId: "cloud-certification", taxonomyVersion: "cloud-certification-taxonomy-v1", axes: ["cloud-domain", "tag"] });
  if (algorithms) await write(root, "manual/source/algorithms/fixture.json", algorithms);
  if (certification) await write(root, "manual/source/cloud-certification/fixture.json", certification);
  if (legacy) await write(root, "tracks/algorithms/banks/legacy.json", algorithmsBatch());
  if (approvals && algorithms) { const ids = algorithms.items.map((item) => item.id); await write(root, "manual/approvals/algorithms/editorial.json", { schemaVersion: "manual-approval-v1", approvalIdentity: "fixture-algorithm-editorial", sourceBatchId: algorithms.sourceBatchId, trackId: "algorithms", contentVersion: algorithms.contentVersion, reviewKind: "editorial", itemIds: ids }); await write(root, "manual/approvals/algorithms/technical.json", { schemaVersion: "manual-approval-v1", approvalIdentity: "fixture-algorithm-technical", sourceBatchId: algorithms.sourceBatchId, trackId: "algorithms", contentVersion: algorithms.contentVersion, reviewKind: "technical", itemIds: ids }); }
  if (approvals && certification) { const ids = certification.items.map((item) => item.id); await write(root, "manual/approvals/cloud-certification/editorial.json", { schemaVersion: "manual-approval-v1", approvalIdentity: "fixture-certification-editorial", sourceBatchId: certification.sourceBatchId, trackId: "cloud-certification", contentVersion: certification.contentVersion, reviewKind: "editorial", itemIds: ids }); await write(root, "manual/approvals/cloud-certification/technical.json", { schemaVersion: "manual-approval-v1", approvalIdentity: "fixture-certification-technical", sourceBatchId: certification.sourceBatchId, trackId: "cloud-certification", contentVersion: certification.contentVersion, reviewKind: "technical", itemIds: ids }); }
}
